import logging
import logging.handlers

# Set up file handlers for the application logs
file_handler = logging.FileHandler('/var/log/application/')
file_handler.setLevel(logging.INFO)
file_handler.setFormatter(logging.Formatter('%(asctime)s - %(name)s - %(levelname)s - %(message)s'))

# Set up log rotation for the application logs
log_rotator = logging.handlers.TimedRotatingFileHandler('/var/log/application/', when='midnight')
log_rotator.setLevel(logging.INFO)
log_rotator.setFormatter(logging.Formatter('%(asctime)s - %(name)s - %(levelname)s - %(message)s'))

# Set up secure storage for the application logs
secure_storage = logging.handlers.RotatingFileHandler('/var/log/application/', maxBytes=1024*1024, backupCount=5)
secure_storage.setLevel(logging.INFO)
secure_storage.setFormatter(logging.Formatter('%(asctime)s - %(name)s - %(levelname)s - %(message)s'))

# Set up the logging configuration for the application
logging.basicConfig(handlers=[file_handler, log_rotator, secure_storage], level=logging.INFO)

# Start the logging system
logging.info('Application started')